import java.util.*;

class Solution {

    /* Function to calculate the length of 
       the Longest Common Subsequence (LCS) 
       using only O(m) space */
    private int lcs(String s1, String s2) {
        int n = s1.length();
        int m = s2.length();

        // prev[] stores results for the previous row
        int[] prev = new int[m + 1];
        // cur[] stores results for the current row
        int[] cur = new int[m + 1];

        // Loop through each character of s1
        for (int ind1 = 1; ind1 <= n; ind1++) {
            // Loop through each character of s2
            for (int ind2 = 1; ind2 <= m; ind2++) {
                // If characters match, extend the LCS length
                if (s1.charAt(ind1 - 1) == s2.charAt(ind2 - 1))
                    cur[ind2] = 1 + prev[ind2 - 1];
                // If not, take the maximum from top or left
                else
                    cur[ind2] = Math.max(prev[ind2], cur[ind2 - 1]);
            }
            // Copy current row to previous row for next iteration
            System.arraycopy(cur, 0, prev, 0, m + 1);
        }

        // LCS length will be in prev[m]
        return prev[m];
    }

    /* Function to calculate the length of 
       the Longest Palindromic Subsequence */
    public int longestPalinSubseq(String s) {
        // Reverse the input string
        String t = new StringBuilder(s).reverse().toString();

        // LPS length is the LCS between s and its reverse
        return lcs(s, t);
    }

    public static void main(String[] args) {
        // Example input
        String s = "bbabcbcab";

        // Create an instance of Solution class
        Solution sol = new Solution();

        // Output the length of the longest palindromic subsequence
        System.out.println("The Length of Longest Palindromic Subsequence is " + sol.longestPalinSubseq(s));
    }
}

